SELECT visit_date, average_rating
FROM market_visits
ORDER BY visit_date DESC;

SELECT market_id, COUNT(review_id) AS total_reviews
FROM market_reviews
GROUP BY market_id;

SELECT average_rating
FROM market_visits
WHERE market_id = 2;

SELECT COUNT(review_id) AS total_reviews
FROM vendor_reviews
WHERE vendor_id = 2;

SELECT vendor_id, COUNT(*) AS total_reviews
FROM vendor_reviews
GROUP BY vendor_id;

SELECT product_type, total_amount
FROM vendor_sales
WHERE verified_transaction = 1;

SELECT market_id, visit_date, total_sales
  FROM market_visits
  WHERE market_id = 1 AND visit_date = '2023-05-01';
